import RNCryptoJS from 'react-native-aes-crypto';
import { ENCRYPTION_KEY_BASE64 } from '../config/keys';

const ALGORITHM = 'aes-256-cbc';
const ENCODING = 'base64';

// Decode the base64 key once on import to use as a Buffer
const ENCRYPTION_KEY = RNCryptoJS.base64.decode(ENCRYPTION_KEY_BASE64);

class CryptoService {
  static async encryptData(data) {
    try {
      // Ensure data is stringified for consistent encryption
      const stringifiedData = JSON.stringify(data);

      // Generate a random IV for each encryption operation.
      // This is crucial for security (prevents identical plaintexts from having identical ciphertexts).
      // RNCryptoJS.randomKey(16) returns a Buffer.
      const ivBuffer = await RNCryptoJS.randomKey(16); 

      const ciphertext = await RNCryptoJS.encrypt(
        stringifiedData,
        ENCRYPTION_KEY, // Use the Buffer key
        ivBuffer,       // Use the Buffer IV
        ALGORITHM,
        ENCODING
      );

      // Return both ciphertext and IV. The IV must be stored alongside the ciphertext
      // to be able to decrypt it later. Base64 encode the IV buffer for storage.
      return {
        ciphertext: ciphertext,
        iv: RNCryptoJS.base64.encode(ivBuffer),
      };
    } catch (error) {
      console.error('Encryption failed:', error);
      throw new Error('Failed to encrypt data');
    }
  }

  static async decryptData(encryptedObject) {
    try {
      if (!encryptedObject || !encryptedObject.ciphertext || !encryptedObject.iv) {
        throw new Error('Invalid encrypted object provided.');
      }

      // Decode the IV from base64 back to its original byte representation (Buffer)
      const ivBuffer = RNCryptoJS.base64.decode(encryptedObject.iv);

      const decryptedText = await RNCryptoJS.decrypt(
        encryptedObject.ciphertext,
        ENCRYPTION_KEY, // Use the Buffer key
        ivBuffer,       // Use the Buffer IV
        ALGORITHM,
        ENCODING
      );

      // Parse the decrypted string back into its original data type
      return JSON.parse(decryptedText);
    } catch (error) {
      console.error('Decryption failed:', error);
      throw new Error('Failed to decrypt data');
    }
  }
}

export default CryptoService;

