import AsyncStorage from '@react-native-async-storage/async-storage';
import CryptoService from './CryptoService';

class SecureStorage {
  static async setItem(key, value) {
    try {
      // Encrypt the value
      const encrypted = await CryptoService.encryptData(value);
      
      // Store the encrypted object (ciphertext + IV) as a JSON string
      await AsyncStorage.setItem(key, JSON.stringify(encrypted));
      return true;
    } catch (error) {
      console.error(`SecureStorage: Failed to set item for key "${key}":`, error);
      return false;
    }
  }

  static async getItem(key) {
    try {
      const encryptedString = await AsyncStorage.getItem(key);
      if (!encryptedString) {
        return null;
      }

      // Parse the stored encrypted object
      const encrypted = JSON.parse(encryptedString);

      // Decrypt the value
      const decryptedValue = await CryptoService.decryptData(encrypted);
      return decryptedValue;
    } catch (error) {
      console.error(`SecureStorage: Failed to get item for key "${key}":`, error);
      return null;
    }
  }

  static async removeItem(key) {
    try {
      await AsyncStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error(`SecureStorage: Failed to remove item for key "${key}":`, error);
      return false;
    }
  }

  static async clear() {
    try {
      await AsyncStorage.clear();
      return true;
    } catch (error) {
      console.error('SecureStorage: Failed to clear all items:', error);
      return false;
    }
  }
}

export default SecureStorage;

